  1	import * as React from 'react';
  2	import { useODFNamespaceSelector } from '@odf/core/redux';
  3	import { PVC_PROVISIONER_ANNOTATION } from '@odf/ocs/constants';
  4	import {
  5	  eventsResource,
  6	  pvcResource,
  7	} from '@odf/ocs/dashboards/persistent-internal/activity-card/activity-card';
  8	import { isSubscriptionUpgradeActivity } from '@odf/ocs/dashboards/persistent-internal/activity-card/ocs-upgrade-activity';
  9	import { isPersistentStorageEvent } from '@odf/ocs/utils';
 10	import { useDeepCompareMemoize } from '@odf/shared/hooks/deep-compare-memoize';
 11	import { subscriptionResource } from '@odf/shared/resources/common';
 12	import { getAnnotations, getName } from '@odf/shared/selectors';
 13	import {
 14	  K8sResourceKind,
 15	  PersistentVolumeClaimKind,
 16	  SubscriptionKind,
 17	} from '@odf/shared/types';
 18	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 19	import { isCephProvisioner } from '@odf/shared/utils';
 20	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 21	import { EventKind } from '@openshift-console/dynamic-plugin-sdk/lib/api/internal-types';
 22	import {
 23	  ActivityBody,
 24	  ActivityItem,
 25	  OngoingActivityBody,
 26	  RecentEventsBody,
 27	} from '@openshift-console/dynamic-plugin-sdk-internal';
 28	import * as _ from 'lodash-es';
 29	import { Card, CardHeader, CardTitle, CardBody } from '@patternfly/react-core';
 30	import { CLIENT_OPERATOR } from '../../../constants';
 31	import '../../../../style.scss';
 32	import './activity-card.scss';
 33	
 34	const ClientOperatorUpgradeActivity: React.FC = () => {
 35	  const { t } = useCustomTranslation();
 36	
 37	  return (
 38	    <ActivityItem>
 39	      {t('Upgrading Data Foundation Client Operator')}
 40	    </ActivityItem>
 41	  );
 42	};
 43	
 44	const getClientOperatorSubscription = (
 45	  subscriptions: K8sResourceKind[]
 46	): SubscriptionKind =>
 47	  _.find(
 48	    subscriptions,
 49	    (item) => item?.spec?.name === CLIENT_OPERATOR
 50	  ) as SubscriptionKind;
 51	
 52	const RecentEvent: React.FC = () => {
 53	  const { odfNamespace } = useODFNamespaceSelector();
 54	
 55	  const [pvcs, pvcLoaded, pvcLoadError] =
 56	    useK8sWatchResource<PersistentVolumeClaimKind[]>(pvcResource);
 57	  const [events, eventsLoaded, eventsLoadError] =
 58	    useK8sWatchResource<EventKind[]>(eventsResource);
 59	
 60	  const validPVC = pvcs
 61	    .filter((obj) =>
 62	      isCephProvisioner(getAnnotations(obj)?.[PVC_PROVISIONER_ANNOTATION])
 63	    )
 64	    .map(getName);
 65	  const memoizedPVCNames = useDeepCompareMemoize(validPVC, true);
 66	
 67	  const clientEventsFilter = React.useCallback(
 68	    () => isPersistentStorageEvent(memoizedPVCNames, odfNamespace),
 69	    [memoizedPVCNames, odfNamespace]
 70	  );
 71	
 72	  const eventObject = {
 73	    data: events,
 74	    loaded: eventsLoaded && pvcLoaded,
 75	    kind: 'Event',
 76	    loadError: pvcLoadError || eventsLoadError,
 77	  };
 78	
 79	  return (
 80	    <RecentEventsBody events={eventObject} filter={clientEventsFilter()} />
 81	  );
 82	};
 83	
 84	const OngoingActivity = () => {
 85	  const [subscriptions, subLoaded] =
 86	    useK8sWatchResource<K8sResourceKind[]>(subscriptionResource);
 87	
 88	  const clientOperatorSubscription: SubscriptionKind =
 89	    getClientOperatorSubscription(subscriptions);
 90	
 91	  const resourceActivities = [];
 92	
 93	  if (isSubscriptionUpgradeActivity(clientOperatorSubscription)) {
 94	    resourceActivities.push({
 95	      resource: clientOperatorSubscription,
 96	      timestamp: clientOperatorSubscription?.status?.lastUpdated,
 97	      component: ClientOperatorUpgradeActivity,
 98	    });
 99	  }
100	
101	  return (
102	    <OngoingActivityBody
103	      loaded={subLoaded}
104	      resourceActivities={resourceActivities}
105	    />
106	  );
107	};
108	
109	export const ActivityCard: React.FC = React.memo(() => {
110	  const { t } = useCustomTranslation();
111	
112	  return (
113	    <Card className="odf-overview-card--gradient">
114	      <CardHeader>
115	        <CardTitle>{t('Activity')}</CardTitle>
116	      </CardHeader>
117	      <CardBody>
118	        <ActivityBody className="odf-client-activity-card__body">
119	          <OngoingActivity />
120	          <RecentEvent />
121	        </ActivityBody>
122	      </CardBody>
123	    </Card>
124	  );
125	});
126	
127	ActivityCard.displayName = 'ActivityCard';
128	
129	export default ActivityCard;

